274	static njs_int_t
275	njs_hash_prototype_update(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
276	    njs_index_t hmac, njs_value_t *retval)
277	{
278	    njs_str_t                    data;
279	    njs_int_t                    ret;
280	    njs_hmac_t                   *ctx;
281	    njs_value_t                  *this, *value;
282	    njs_digest_t                 *dgst;
283	    njs_opaque_value_t           result;
284	    const njs_buffer_encoding_t  *enc;
285	
286	    this = njs_argument(args, 0);
287	
288	    if (!hmac) {
289	        dgst = njs_vm_external(vm, njs_crypto_hash_proto_id, this);
290	        if (njs_slow_path(dgst == NULL)) {
291	            njs_vm_type_error(vm, "\"this\" is not a hash object");
292	            return NJS_ERROR;
293	        }
294	
295	        if (njs_slow_path(dgst->ctx == NULL)) {
296	            njs_vm_error(vm, "Digest already called");
297	            return NJS_ERROR;
298	        }
299	
300	        ctx = NULL;
301	
302	    } else {
303	        ctx = njs_vm_external(vm, njs_crypto_hmac_proto_id, this);
304	        if (njs_slow_path(ctx == NULL)) {
305	            njs_vm_type_error(vm, "\"this\" is not a hmac object");
306	            return NJS_ERROR;
307	        }
308	
309	        if (njs_slow_path(ctx->ctx == NULL)) {
310	            njs_vm_error(vm, "Digest already called");
311	            return NJS_ERROR;
312	        }
313	
314	        dgst = NULL;
315	    }
316	
317	    value = njs_arg(args, nargs, 1);
318	
319	    if (njs_value_is_string(value)) {
320	        enc = njs_buffer_encoding(vm, njs_arg(args, nargs, 2), 1);
321	        if (njs_slow_path(enc == NULL)) {
322	            return NJS_ERROR;
323	        }
324	
325	        ret = njs_buffer_decode_string(vm, value, njs_value_arg(&result), enc);
326	        if (njs_slow_path(ret != NJS_OK)) {
327	            return NJS_ERROR;
328	        }
329	
330	        njs_value_string_get(vm, njs_value_arg(&result), &data);
331	
332	    } else if (njs_value_is_buffer(value)) {
333	        ret = njs_value_buffer_get(vm, value, &data);
334	        if (njs_slow_path(ret != NJS_OK)) {
335	            return NJS_ERROR;
336	        }
337	
338	    } else {
339	        njs_vm_type_error(vm, "data is not a string or Buffer-like object");
340	
341	        return NJS_ERROR;
342	    }
343	
344	    if (!hmac) {
345	        if (EVP_DigestUpdate(dgst->ctx, data.start, data.length) <= 0) {
346	            njs_vm_internal_error(vm, "EVP_DigestUpdate() failed");
347	            return NJS_ERROR;
348	        }
349	
350	    } else {
351	        if (HMAC_Update(ctx->ctx, data.start, data.length) <= 0) {
352	            njs_vm_internal_error(vm, "HMAC_Update() failed");
353	            return NJS_ERROR;
354	        }
355	    }
356	
357	    njs_value_assign(retval, this);
358	
359	    return NJS_OK;
360	}
