363	static njs_int_t
364	njs_hash_prototype_digest(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
365	    njs_index_t hmac, njs_value_t *retval)
366	{
367	    njs_str_t         str;
368	    njs_hmac_t        *ctx;
369	    njs_value_t       *this;
370	    njs_digest_t      *dgst;
371	    unsigned int      len;
372	    njs_crypto_enc_t  *enc;
373	    u_char            digest[EVP_MAX_MD_SIZE];
374	
375	    this = njs_argument(args, 0);
376	
377	    if (!hmac) {
378	        dgst = njs_vm_external(vm, njs_crypto_hash_proto_id, this);
379	        if (njs_slow_path(dgst == NULL)) {
380	            njs_vm_type_error(vm, "\"this\" is not a hash object");
381	            return NJS_ERROR;
382	        }
383	
384	        if (njs_slow_path(dgst->ctx == NULL)) {
385	            goto exception;
386	        }
387	
388	        ctx = NULL;
389	
390	    } else {
391	        ctx = njs_vm_external(vm, njs_crypto_hmac_proto_id, this);
392	        if (njs_slow_path(ctx == NULL)) {
393	            njs_vm_type_error(vm, "\"this\" is not a hmac object");
394	            return NJS_ERROR;
395	        }
396	
397	        if (njs_slow_path(ctx->ctx == NULL)) {
398	            goto exception;
399	        }
400	
401	        dgst = NULL;
402	    }
403	
404	    enc = njs_crypto_encoding(vm, njs_arg(args, nargs, 1));
405	    if (njs_slow_path(enc == NULL)) {
406	        return NJS_ERROR;
407	    }
408	
409	    if (!hmac) {
410	        if (EVP_DigestFinal_ex(dgst->ctx, digest, &len) <= 0) {
411	            njs_vm_internal_error(vm, "EVP_DigestFinal_ex() failed");
412	            return NJS_ERROR;
413	        }
414	
415	        njs_evp_md_ctx_free(dgst->ctx);
416	        dgst->ctx = NULL;
417	
418	    } else {
419	        if (HMAC_Final(ctx->ctx, digest, &len) <= 0) {
420	            njs_vm_internal_error(vm, "HMAC_Final() failed");
421	            return NJS_ERROR;
422	        }
423	
424	        njs_hmac_ctx_free(ctx->ctx);
425	        ctx->ctx = NULL;
426	    }
427	
428	    str.start = digest;
429	    str.length = len;
430	
431	    return enc->encode(vm, retval, &str);
432	
433	exception:
434	
435	    njs_vm_error(vm, "Digest already called");
436	
437	    return NJS_ERROR;
438	}
