568	static const EVP_MD *
569	njs_crypto_algorithm(njs_vm_t *vm, njs_value_t *value)
570	{
571	    njs_str_t     name;
572	    const EVP_MD  *md;
573	
574	    if (njs_slow_path(!njs_value_is_string(value))) {
575	        njs_vm_type_error(vm, "algorithm must be a string");
576	        return NULL;
577	    }
578	
579	    njs_value_string_get(vm, value, &name);
580	
581	    if (njs_slow_path(njs_strlen(name.start) != name.length)) {
582	        njs_vm_type_error(vm, "not supported algorithm: \"%V\"", &name);
583	        return NULL;
584	    }
585	
586	    md = EVP_get_digestbyname((const char *) name.start);
587	    if (njs_slow_path(md == NULL)) {
588	        njs_vm_type_error(vm, "not supported algorithm: \"%V\"", &name);
589	        return NULL;
590	    }
591	
592	    return md;
593	}
