596	static njs_crypto_enc_t *
597	njs_crypto_encoding(njs_vm_t *vm, njs_value_t *value)
598	{
599	    njs_str_t         name;
600	    njs_crypto_enc_t  *e;
601	
602	    if (njs_slow_path(!njs_value_is_string(value))) {
603	        if (!njs_value_is_undefined(value)) {
604	            njs_vm_type_error(vm, "encoding must be a string");
605	            return NULL;
606	        }
607	
608	        return &njs_encodings[0];
609	    }
610	
611	    njs_value_string_get(vm, value, &name);
612	
613	    for (e = &njs_encodings[1]; e->name.length != 0; e++) {
614	        if (njs_strstr_eq(&name, &e->name)) {
615	            return e;
616	        }
617	    }
618	
619	    njs_vm_type_error(vm, "Unknown digest encoding: \"%V\"", &name);
620	
621	    return NULL;
622	}
