665	                                               njs_nitems(njs_ext_crypto_hash));
666	    if (njs_slow_path(njs_crypto_hash_proto_id < 0)) {
667	        return NJS_ERROR;
668	    }
669	
670	    njs_crypto_hmac_proto_id =
671	                     njs_vm_external_prototype(vm, njs_ext_crypto_hmac,
672	                                               njs_nitems(njs_ext_crypto_hmac));
673	    if (njs_slow_path(njs_crypto_hmac_proto_id < 0)) {
674	        return NJS_ERROR;
675	    }
676	
677	    proto_id = njs_vm_external_prototype(vm, njs_ext_crypto_crypto,
678	                                         njs_nitems(njs_ext_crypto_crypto));
679	    if (njs_slow_path(proto_id < 0)) {
680	        return NJS_ERROR;
681	    }
682	
683	    ret = njs_vm_external_create(vm, njs_value_arg(&value), proto_id, NULL, 1);
684	    if (njs_slow_path(ret != NJS_OK)) {
685	        return NJS_ERROR;
686	    }
687	
688	    module = njs_vm_add_module(vm, &njs_str_value("crypto"),
689	                               njs_value_arg(&value));
