119	static JSValue
120	qjs_crypto_create_hash(JSContext *cx, JSValueConst this_val, int argc,
121	    JSValueConst *argv)
122	{
123	    JSValue       obj;
124	    qjs_digest_t  *dgst;
125	    const EVP_MD  *md;
126	
127	    md = qjs_crypto_algorithm(cx, argv[0]);
128	    if (md == NULL) {
129	        return JS_EXCEPTION;
130	    }
131	
132	    dgst = js_malloc(cx, sizeof(qjs_digest_t));
133	    if (dgst == NULL) {
134	        return JS_ThrowOutOfMemory(cx);
135	    }
136	
137	    dgst->ctx = njs_evp_md_ctx_new();
138	    if (dgst->ctx == NULL) {
139	        js_free(cx, dgst);
140	        return JS_ThrowOutOfMemory(cx);
141	    }
142	
143	    if (EVP_DigestInit_ex(dgst->ctx, md, NULL) <= 0) {
144	        njs_evp_md_ctx_free(dgst->ctx);
145	        js_free(cx, dgst);
146	        JS_ThrowInternalError(cx, "EVP_DigestInit_ex() failed");
147	        return JS_EXCEPTION;
148	    }
149	
150	    obj = JS_NewObjectClass(cx, QJS_CORE_CLASS_CRYPTO_HASH);
151	    if (JS_IsException(obj)) {
152	        njs_evp_md_ctx_free(dgst->ctx);
153	        js_free(cx, dgst);
154	        return obj;
155	    }
156	
157	    JS_SetOpaque(obj, dgst);
158	
159	    return obj;
