163	static JSValue
164	qjs_hash_prototype_update(JSContext *cx, JSValueConst this_val, int argc,
165	    JSValueConst *argv, int hmac)
166	{
167	    njs_str_t                    str, content;
168	    qjs_hmac_t                   *hctx;
169	    qjs_bytes_t                  bytes;
170	    qjs_digest_t                 *dgst;
171	    const qjs_buffer_encoding_t  *enc;
172	
173	    if (!hmac) {
174	        dgst = JS_GetOpaque2(cx, this_val, QJS_CORE_CLASS_CRYPTO_HASH);
175	        if (dgst == NULL) {
176	            return JS_ThrowTypeError(cx, "\"this\" is not a hash object");
177	        }
178	
179	        if (dgst->ctx == NULL) {
180	            return JS_ThrowTypeError(cx, "Digest already called");
181	        }
182	
183	        hctx = NULL;
184	
185	    } else {
186	        hctx = JS_GetOpaque2(cx, this_val, QJS_CORE_CLASS_CRYPTO_HMAC);
187	        if (hctx == NULL) {
188	            return JS_ThrowTypeError(cx, "\"this\" is not a hmac object");
189	        }
190	
191	        if (hctx->ctx == NULL) {
192	            return JS_ThrowTypeError(cx, "Digest already called");
193	        }
194	
195	        dgst = NULL;
196	    }
197	
198	    if (JS_IsString(argv[0])) {
199	        enc = qjs_buffer_encoding(cx, argv[1], 1);
200	        if (enc == NULL) {
201	            return JS_EXCEPTION;
202	        }
203	
204	        str.start = (u_char *) JS_ToCStringLen(cx, &str.length, argv[0]);
205	        if (str.start == NULL) {
206	            return JS_EXCEPTION;
207	        }
208	
209	        if (enc->decode_length != NULL) {
210	            content.length = enc->decode_length(cx, &str);
211	            content.start = js_malloc(cx, content.length);
212	            if (content.start == NULL) {
213	                JS_FreeCString(cx, (const char *) str.start);
214	                return JS_ThrowOutOfMemory(cx);
215	            }
216	
217	            if (enc->decode(cx, &str, &content) != 0) {
218	                JS_FreeCString(cx, (const char *) str.start);
219	                js_free(cx, content.start);
220	                return JS_EXCEPTION;
221	            }
222	
223	            JS_FreeCString(cx, (const char *) str.start);
224	
225	            if (!hmac) {
226	                if (EVP_DigestUpdate(dgst->ctx, content.start, content.length)
227	                    <= 0)
228	                {
229	                    js_free(cx, content.start);
230	                    JS_ThrowInternalError(cx, "EVP_DigestUpdate() failed");
231	                    return JS_EXCEPTION;
232	                }
233	
234	            } else {
235	                if (HMAC_Update(hctx->ctx, content.start, content.length) <= 0)
236	                {
237	                    js_free(cx, content.start);
238	                    JS_ThrowInternalError(cx, "HMAC_Update() failed");
239	                    return JS_EXCEPTION;
240	                }
241	            }
242	
243	            js_free(cx, content.start);
244	
245	        } else {
246	            if (!hmac) {
247	                if (EVP_DigestUpdate(dgst->ctx, str.start, str.length) <= 0) {
248	                    JS_FreeCString(cx, (const char *) str.start);
249	                    JS_ThrowInternalError(cx, "EVP_DigestUpdate() failed");
250	                    return JS_EXCEPTION;
251	                }
252	
253	            } else {
254	                if (HMAC_Update(hctx->ctx, str.start, str.length) <= 0) {
255	                    JS_FreeCString(cx, (const char *) str.start);
256	                    JS_ThrowInternalError(cx, "HMAC_Update() failed");
257	                    return JS_EXCEPTION;
258	                }
259	            }
260	
261	            JS_FreeCString(cx, (const char *) str.start);
262	        }
263	
264	    } else if (qjs_is_typed_array(cx, argv[0])) {
265	        if (qjs_to_bytes(cx, &bytes, argv[0]) != 0) {
266	            return JS_EXCEPTION;
267	        }
268	
269	        if (!hmac) {
270	            if (EVP_DigestUpdate(dgst->ctx, bytes.start, bytes.length) <= 0) {
271	                JS_ThrowInternalError(cx, "EVP_DigestUpdate() failed");
272	                return JS_EXCEPTION;
273	            }
274	
275	        } else {
276	            if (HMAC_Update(hctx->ctx, bytes.start, bytes.length) <= 0) {
277	                JS_ThrowInternalError(cx, "HMAC_Update() failed");
278	                return JS_EXCEPTION;
279	            }
280	        }
281	
282	    } else {
283	        return JS_ThrowTypeError(cx,
284	                                 "data is not a string or Buffer-like object");
285	    }
286	
287	    return JS_DupValue(cx, this_val);
288	}
