291	static JSValue
292	qjs_hash_prototype_digest(JSContext *cx, JSValueConst this_val, int argc,
293	    JSValueConst *argv, int hmac)
294	{
295	    njs_str_t         str;
296	    unsigned int      len;
297	    qjs_hmac_t        *hctx;
298	    qjs_digest_t      *dgst;
299	    qjs_crypto_enc_t  *enc;
300	    u_char            digest[EVP_MAX_MD_SIZE];
301	
302	    if (!hmac) {
303	        dgst = JS_GetOpaque2(cx, this_val, QJS_CORE_CLASS_CRYPTO_HASH);
304	        if (dgst == NULL) {
305	            return JS_ThrowTypeError(cx, "\"this\" is not a hash object");
306	        }
307	
308	        if (dgst->ctx == NULL) {
309	            return JS_ThrowTypeError(cx, "Digest already called");
310	        }
311	
312	        if (EVP_DigestFinal_ex(dgst->ctx, digest, &len) <= 0) {
313	            JS_ThrowInternalError(cx, "EVP_DigestFinal_ex() failed");
314	            return JS_EXCEPTION;
315	        }
316	
317	        njs_evp_md_ctx_free(dgst->ctx);
318	        dgst->ctx = NULL;
319	
320	    } else {
321	        hctx = JS_GetOpaque2(cx, this_val, QJS_CORE_CLASS_CRYPTO_HMAC);
322	        if (hctx == NULL) {
323	            return JS_ThrowTypeError(cx, "\"this\" is not a hmac object");
324	        }
325	
326	        if (hctx->ctx == NULL) {
327	            return JS_ThrowTypeError(cx, "Digest already called");
328	        }
329	
330	        if (HMAC_Final(hctx->ctx, digest, &len) <= 0) {
331	            JS_ThrowInternalError(cx, "HMAC_Final() failed");
332	            return JS_EXCEPTION;
333	        }
334	
335	        njs_hmac_ctx_free(hctx->ctx);
336	        hctx->ctx = NULL;
337	    }
338	
339	    str.start = digest;
340	    str.length = len;
341	
342	    if (argc == 0) {
343	        return qjs_buffer_digest(cx, &str);
344	    }
345	
346	    enc = qjs_crypto_encoding(cx, argv[0]);
347	    if (enc == NULL) {
348	        return JS_EXCEPTION;
349	    }
350	
351	    return enc->encode(cx, &str);
352	}
