384	        js_free(cx, copy);
385	        JS_ThrowInternalError(cx, "EVP_MD_CTX_copy_ex() failed");
386	        return JS_EXCEPTION;
387	    }
388	
389	    obj = JS_NewObjectClass(cx, QJS_CORE_CLASS_CRYPTO_HASH);
390	    if (JS_IsException(obj)) {
391	        njs_evp_md_ctx_free(copy->ctx);
392	        js_free(cx, copy);
