402	static JSValue
403	qjs_crypto_create_hmac(JSContext *cx, JSValueConst this_val, int argc,
404	    JSValueConst *argv)
405	{
406	    JS_BOOL       key_is_string;
407	    JSValue       obj;
408	    njs_str_t     key;
409	    qjs_hmac_t    *hmac;
410	    qjs_bytes_t   bytes;
411	    const EVP_MD  *md;
412	
413	    md = qjs_crypto_algorithm(cx, argv[0]);
414	    if (md == NULL) {
415	        return JS_EXCEPTION;
416	    }
417	
418	    key_is_string = JS_IsString(argv[1]);
419	    if (key_is_string) {
420	        key.start = (u_char *) JS_ToCStringLen(cx, &key.length, argv[1]);
421	        if (key.start == NULL) {
422	            return JS_EXCEPTION;
423	        }
424	
425	    } else if (qjs_is_typed_array(cx, argv[1])) {
426	        if (qjs_to_bytes(cx, &bytes, argv[1]) != 0) {
427	            return JS_EXCEPTION;
428	        }
429	
430	        key.start = bytes.start;
431	        key.length = bytes.length;
432	
433	    } else {
434	        return JS_ThrowTypeError(cx,
435	                                 "key is not a string or Buffer-like object");
436	    }
437	
438	    hmac = js_malloc(cx, sizeof(qjs_hmac_t));
439	    if (hmac == NULL) {
440	        if (key_is_string) {
441	            JS_FreeCString(cx, (const char *) key.start);
442	        }
443	
444	        return JS_ThrowOutOfMemory(cx);
445	    }
446	
447	    hmac->ctx = njs_hmac_ctx_new();
448	    if (hmac->ctx == NULL) {
449	        js_free(cx, hmac);
450	        if (key_is_string) {
451	            JS_FreeCString(cx, (const char *) key.start);
452	        }
453	
454	        return JS_ThrowOutOfMemory(cx);
455	    }
456	
457	    if (HMAC_Init_ex(hmac->ctx, key.start, (int) key.length, md, NULL) <= 0) {
458	        njs_hmac_ctx_free(hmac->ctx);
459	        js_free(cx, hmac);
460	        if (key_is_string) {
461	            JS_FreeCString(cx, (const char *) key.start);
462	        }
463	
464	        JS_ThrowInternalError(cx, "HMAC_Init_ex() failed");
465	        return JS_EXCEPTION;
466	    }
467	
468	    if (key_is_string) {
469	        JS_FreeCString(cx, (const char *) key.start);
470	    }
471	
472	    obj = JS_NewObjectClass(cx, QJS_CORE_CLASS_CRYPTO_HMAC);
473	    if (JS_IsException(obj)) {
474	        njs_hmac_ctx_free(hmac->ctx);
475	        js_free(cx, hmac);
476	        return obj;
477	    }
478	
479	    JS_SetOpaque(obj, hmac);
480	
481	    return obj;
482	}
