517	static const EVP_MD *
518	qjs_crypto_algorithm(JSContext *cx, JSValueConst val)
519	{
520	    size_t        len;
521	    const char    *name;
522	    const EVP_MD  *md;
523	
524	    name = JS_ToCStringLen(cx, &len, val);
525	    if (name == NULL) {
526	        JS_ThrowTypeError(cx, "algorithm must be a string");
527	        return NULL;
528	    }
529	
530	    if (njs_strlen(name) != len) {
531	        JS_FreeCString(cx, name);
532	        JS_ThrowTypeError(cx, "not supported algorithm");
533	        return NULL;
534	    }
535	
536	    md = EVP_get_digestbyname(name);
537	
538	    JS_FreeCString(cx, name);
539	
540	    if (md == NULL) {
541	        JS_ThrowTypeError(cx, "not supported algorithm");
542	        return NULL;
543	    }
544	
545	    return md;
546	}
