549	static qjs_crypto_enc_t *
550	qjs_crypto_encoding(JSContext *cx, JSValueConst val)
551	{
552	    njs_str_t         name;
553	    qjs_crypto_enc_t  *e, *enc;
554	
555	    if (JS_IsNullOrUndefined(val)) {
556	        return &qjs_encodings[0];
557	    }
558	
559	    name.start = (u_char *) JS_ToCStringLen(cx, &name.length, val);
560	    if (name.start == NULL) {
561	        return NULL;
562	    }
563	
564	    enc = NULL;
565	
566	    for (e = &qjs_encodings[1]; e->name.start != NULL; e++) {
567	        if (njs_strstr_eq(&name, &e->name)) {
568	            enc = e;
569	            break;
570	        }
571	    }
572	
573	    JS_FreeCString(cx, (const char *) name.start);
574	
575	    if (enc == NULL) {
576	        JS_ThrowTypeError(cx, "Unknown digest encoding");
577	    }
578	
579	    return enc;
580	}
