590	static int
591	qjs_crypto_module_init(JSContext *cx, JSModuleDef *m)
592	{
593	    JSValue crypto_obj;
594	
595	    crypto_obj = JS_NewObject(cx);
596	    if (JS_IsException(crypto_obj)) {
597	        return -1;
598	    }
599	
600	    JS_SetPropertyFunctionList(cx, crypto_obj, qjs_crypto_export,
601	                               njs_nitems(qjs_crypto_export));
602	
603	    if (JS_SetModuleExport(cx, m, "default", crypto_obj) != 0) {
604	        return -1;
605	    }
606	
607	    return JS_SetModuleExportList(cx, m, qjs_crypto_export,
608	                                  njs_nitems(qjs_crypto_export));
609	}
