611	
612	static JSModuleDef *
613	qjs_crypto_init(JSContext *cx, const char *module_name)
614	{
615	    JSValue      proto;
616	    JSModuleDef  *m;
617	
618	    if (!JS_IsRegisteredClass(JS_GetRuntime(cx),
619	                              QJS_CORE_CLASS_CRYPTO_HASH))
620	    {
621	        if (JS_NewClass(JS_GetRuntime(cx), QJS_CORE_CLASS_CRYPTO_HASH,
622	                        &qjs_hash_class) < 0)
623	        {
624	            return NULL;
625	        }
626	
627	        proto = JS_NewObject(cx);
628	        if (JS_IsException(proto)) {
629	            return NULL;
630	        }
631	
632	        JS_SetPropertyFunctionList(cx, proto, qjs_hash_proto_proto,
633	                                   njs_nitems(qjs_hash_proto_proto));
634	
635	        JS_SetClassProto(cx, QJS_CORE_CLASS_CRYPTO_HASH, proto);
636	
637	        if (JS_NewClass(JS_GetRuntime(cx), QJS_CORE_CLASS_CRYPTO_HMAC,
638	                        &qjs_hmac_class) < 0)
639	        {
640	            return NULL;
641	        }
642	
643	        proto = JS_NewObject(cx);
644	        if (JS_IsException(proto)) {
645	            return NULL;
646	        }
647	
648	        JS_SetPropertyFunctionList(cx, proto, qjs_hmac_proto_proto,
649	                                   njs_nitems(qjs_hmac_proto_proto));
650	
651	        JS_SetClassProto(cx, QJS_CORE_CLASS_CRYPTO_HMAC, proto);
652	    }
653	
654	    m = JS_NewCModule(cx, module_name, qjs_crypto_module_init);
655	    if (m == NULL) {
656	        return NULL;
657	    }
658	
659	    if (JS_AddModuleExport(cx, m, "default") < 0) {
660	        return NULL;
661	    }
662	
663	    if (JS_AddModuleExportList(cx, m, qjs_crypto_export,
664	                           njs_nitems(qjs_crypto_export)) != 0)
665	    {
666	        return NULL;
667	    }
668	
669	    return m;
670	}
